import requests
names = [
    'flag', 'Flag', 'FLAG', 'flag.txt', 'Flag.txt', 'FLAG.txt', 'flag.html', 'flag.php', 'flag.png',
    'flag.jpeg', 'flag.gif', 'flag.bmp', 'flag/index.html', 'flag/FLAG.txt', 'flag/flag.txt',
    'FLAG/flag.txt', 'FLAG.TXT', 'flag.tar.gz', 'flag.zip', 'flag/secret.txt'
]
for name in names:
    try:
        r = requests.get(f'http://192.168.5.4/{name}', timeout=3)
        if r.status_code == 200:
            print(name, '=>', r.text[:200])
        else:
            print(name, '=>', r.status_code)
    except Exception as e:
        print(name, '=>', 'error', e)
